using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportingFunction
{
    [FunctionName("QueryReportingData")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var parameters = new Dictionary<string, object>();
            
            foreach (var param in req.Query)
            {
                if (!string.IsNullOrEmpty(param.Value.ToString()))
                {
                    parameters[param.Key] = param.Value.ToString();
                }
            }
            
            var sqlQuery = BuildDynamicQuery(parameters);
            
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(sqlQuery, connection))
                {
                    foreach (var param in parameters)
                    {
                        if (param.Key != "table" && param.Key != "columns")
                        {
                            command.Parameters.AddWithValue($"@{param.Key}", param.Value);
                        }
                    }
                    
                    var reader = await command.ExecuteReaderAsync();
                    var results = new List<Dictionary<string, object>>();
                    
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            row[reader.GetName(i)] = reader.GetValue(i);
                        }
                        results.Add(row);
                    }
                    
                    return new OkObjectResult(results);
                }
            }
        }
        catch (Exception ex)
        {
            return new BadRequestObjectResult($"Error: {ex.Message}");
        }
    }
    
    private static string BuildDynamicQuery(Dictionary<string, object> parameters)
    {
        var table = parameters.ContainsKey("table") ? parameters["table"].ToString() : "YourTable";
        var columns = parameters.ContainsKey("columns") ? parameters["columns"].ToString() : "*";
        
        var query = $"SELECT {columns} FROM {table} WHERE 1=1";
        
        foreach (var param in parameters)
        {
            if (param.Key != "table" && param.Key != "columns")
            {
                query += $" AND {param.Key} = @{param.Key}";
            }
        }
        
        return query;
    }
